const BATCH = 10;

function parseMeta(raw) {
  if (!raw) return {};
  try {
    return typeof raw === 'string' ? JSON.parse(raw) : raw;
  } catch {
    return {};
  }
}

const res = $input.first().json;
const rows = Array.isArray(res.values) ? res.values : [];
if (rows.length < 2) {
  return [{ json: { empty: true, message: 'content_drafts trống' } }];
}

const headers = rows[0].map((x) => String(x ?? '').trim().toLowerCase());
const out = [];

for (let i = 1; i < rows.length; i++) {
  const cells = rows[i];
  if (!cells?.some((c) => String(c ?? '').trim())) continue;

  const row = { sheet_row: i + 1 };
  headers.forEach((key, j) => {
    if (key) row[key] = cells[j] ?? '';
  });

  const status = String(row.status || '').trim().toLowerCase();
  const meta = parseMeta(row.meta);

  if (meta.outreach_created === true) continue;
  if (status !== 'draft' && status !== 'approved') continue;

  const title = String(row.title || '').trim();
  const hook = String(row.hook_line || '').trim();
  if (!title || !hook) continue;

  out.push({ json: row });
  if (out.length >= BATCH) break;
}

if (!out.length) {
  return [{ json: { empty: true, message: 'Không còn draft chờ outreach (status=draft, chưa outreach)' } }];
}

return out;

const data = $getWorkflowStaticData('global');
data.a4_stats = { outreach_ok: 0, l0_fail: 0, l1_fail: 0, parse_fail: 0 };
return $input.all();

const MAGNIX_LLM_DEFAULTS = {"classify":"deepseek","editorial_brief":"deepseek","outreach":"deepseek","video_draft":"deepseek","carousel_draft":"deepseek","content_draft":"anthropic","content_draft_general":"deepseek","content_qa":"anthropic","housex_article":"anthropic"};

function hasLlmKey(raw) {
  return String(raw || '').trim().length > 12;
}

function envProvider(taskId) {
  const key = `MAGNIX_LLM_${String(taskId || '')
    .toUpperCase()
    .replace(/[^A-Z0-9]/g, '_')}_PROVIDER`;
  const v = String($env[key] || '').trim().toLowerCase();
  if (v === 'deepseek' || v === 'anthropic') return v;
  return null;
}

function resolveProvider(taskId) {
  return envProvider(taskId) || MAGNIX_LLM_DEFAULTS[taskId] || 'deepseek';
}

function hasProvider(provider) {
  if (provider === 'anthropic') return hasLlmKey($env.ANTHROPIC_API_KEY);
  return hasLlmKey($env.DEEPSEEK_API_KEY);
}

function anthropicModelForTask(taskId) {
  if (taskId === 'classify') {
    return $env.ANTHROPIC_CLASSIFY_MODEL || 'claude-haiku-4-5-20251001';
  }
  if (taskId === 'video_draft') {
    return $env.ANTHROPIC_VIDEO_MODEL || $env.ANTHROPIC_DRAFT_MODEL || 'claude-sonnet-4-6';
  }
  return $env.ANTHROPIC_DRAFT_MODEL || $env.ANTHROPIC_MODEL || 'claude-sonnet-4-6';
}

async function callDeepSeekLlm(ctx, opts) {
  const {
    system,
    userPayload,
    temperature = 0.35,
    maxTokens = 4096,
    jsonMode = true,
  } = opts;
  return ctx.helpers.httpRequest({
    method: 'POST',
    url: $env.DEEPSEEK_API_URL || 'https://api.deepseek.com/chat/completions',
    headers: {
      Authorization: `Bearer ${$env.DEEPSEEK_API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: {
      model: $env.DEEPSEEK_MODEL || 'deepseek-chat',
      temperature,
      max_tokens: maxTokens,
      ...(jsonMode ? { response_format: { type: 'json_object' } } : {}),
      messages: [
        { role: 'system', content: system },
        { role: 'user', content: userPayload },
      ],
    },
    json: true,
  });
}

async function callAnthropicLlm(ctx, opts) {
  const {
    system,
    userPayload,
    temperature = 0.35,
    maxTokens = 4096,
    taskId = 'content_draft',
  } = opts;
  return ctx.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: {
      'x-api-key': $env.ANTHROPIC_API_KEY,
      'anthropic-version': '2023-06-01',
      'Content-Type': 'application/json',
    },
    body: {
      model: anthropicModelForTask(taskId),
      max_tokens: maxTokens,
      temperature,
      system,
      messages: [{ role: 'user', content: userPayload }],
    },
    json: true,
  });
}

async function invokeMagnixLlm(ctx, taskId, opts) {
  const primary = resolveProvider(taskId);
  const fallback = primary === 'deepseek' ? 'anthropic' : 'deepseek';
  const errors = [];

  for (const provider of [primary, fallback]) {
    if (!hasProvider(provider)) continue;
    try {
      if (provider === 'deepseek') {
        return await callDeepSeekLlm(ctx, opts);
      }
      return await callAnthropicLlm(ctx, { ...opts, taskId });
    } catch (e) {
      errors.push(`${provider}: ${e.message}`);
    }
  }

  if (!hasProvider('deepseek') && !hasProvider('anthropic')) {
    throw new Error('Thiếu DEEPSEEK_API_KEY hoặc ANTHROPIC_API_KEY trên n8n env');
  }
  throw new Error(errors.join(' | ') || 'LLM providers failed');
}

// Shared outreach context — inlined vào Agent 4 LLM node lúc build.
// Tests: tests/resolve-outreach-context.test.mjs

function parseOutreachMeta(raw) {
  if (!raw) return {};
  try {
    return typeof raw === 'string' ? JSON.parse(raw) : raw;
  } catch {
    return {};
  }
}

const WARMTH_TO_CONTEXT = {
  cold: 'cold',
  commented: 'sau_comment',
  sau_comment: 'sau_comment',
  dm_inbound: 'sau_comment',
  dm: 'sau_comment',
  ads_optin: 'sau_comment',
  partner: 'cold',
  follow_up: 'follow_up',
};

function resolveOutreachContext(row) {
  const meta = parseOutreachMeta(row?.meta);
  const warmth = String(meta.outreach_warmth || meta.warmth || 'cold').trim().toLowerCase();
  const contextOverride = String(meta.outreach_context || '').trim().toLowerCase();

  if (contextOverride && ['cold', 'sau_comment', 'follow_up'].includes(contextOverride)) {
    return { warmth, context: contextOverride };
  }

  return { warmth, context: WARMTH_TO_CONTEXT[warmth] || 'cold' };
}

function primaryVariantForContext(context) {
  if (context === 'sau_comment') return 'variant_b_after_engagement';
  if (context === 'follow_up') return 'variant_c_follow_up';
  return 'variant_a_cold';
}

const row = $('Loop Outreach Candidates').item?.json || $input.first().json;
const { warmth, context } = resolveOutreachContext(row);

const system = `Trợ lý Magnix — Value-First outreach. [/ghost] [/brief]
Chỉ trả JSON hợp lệ:
{"segment":"","variant_a_cold":"","variant_b_after_engagement":"","variant_c_follow_up":"","ghost_check_passed":true,"compliance_note":""}
- variant_a_cold: ≤3 dòng, ≤280 ký tự (cold open)
- variant_b_after_engagement: ≤4 câu (sau comment/DM/opt-in)
- variant_c_follow_up: nhẹ, thoát gracefully
- context=${context}: ưu tiên biến thể phù hợp context nhưng vẫn sinh đủ 3 variant
- Cấm: "Trong kỷ nguyên số", "Hơn nữa", "Tóm lại", "cam kết", "Đừng bỏ lỡ"`;

const userPayload = JSON.stringify({
  segment: row.segment || 'general_inbound',
  pain: String(row.hook_line || '').slice(0, 500),
  lead_magnet_title: row.title,
  context,
  warmth,
  channel: 'zalo',
  source_normalized_key: row.source_normalized_key,
});

try {
  const res = await invokeMagnixLlm(this, 'outreach', {
    system,
    userPayload,
    temperature: 0.5,
    maxTokens: 1024,
    jsonMode: true,
  });
  return [{ json: { ...res, outreach_warmth: warmth, outreach_context: context } }];
} catch (e) {
  return [{ json: { error: true, message: e.message } }];
}

function extractJsonString(raw) {
  if (raw == null) throw new Error('EMPTY_LLM_OUTPUT');
  const s = typeof raw === 'string' ? raw : JSON.stringify(raw);
  const fenced = s.match(/```(?:json)?\s*([\s\S]*?)```/i);
  return (fenced ? fenced[1] : s).trim();
}

const res = $input.first().json;
const raw =
  res.choices?.[0]?.message?.content ??
  res.content?.[0]?.text ??
  res.message?.content ??
  res;

try {
  const parsed = JSON.parse(extractJsonString(raw));
  const required = ['segment', 'variant_a_cold', 'variant_b_after_engagement', 'variant_c_follow_up'];
  for (const k of required) {
    if (!parsed[k] || !String(parsed[k]).trim()) throw new Error(`MISSING_${k.toUpperCase()}`);
  }
  return [{
    json: {
      ok: true,
      outreach_warmth: res.outreach_warmth,
      outreach_context: res.outreach_context,
      outreach: {
        segment: String(parsed.segment),
        variant_a_cold: String(parsed.variant_a_cold).slice(0, 500),
        variant_b_after_engagement: String(parsed.variant_b_after_engagement).slice(0, 1500),
        variant_c_follow_up: String(parsed.variant_c_follow_up).slice(0, 1000),
        ghost_check_passed: parsed.ghost_check_passed !== false,
        compliance_note: String(parsed.compliance_note || '').slice(0, 500),
      },
    },
  }];
} catch (e) {
  return [{ json: { ok: false, parse_error: e.message, raw_preview: String(raw).slice(0, 200) } }];
}

const FORBIDDEN = [
  /trong kỷ nguyên số/i,
  /hơn nữa/i,
  /tóm lại/i,
  /cam kết/i,
  /đừng bỏ lỡ/i,
  /rất vui được/i,
];

const item = $input.first().json;
if (!item.ok || !item.outreach) {
  return [{ json: { ...item, l0_pass: false, l1_pass: false } }];
}

const o = item.outreach;
const text = [o.variant_a_cold, o.variant_b_after_engagement, o.variant_c_follow_up].join('\n');

const l0_hits = FORBIDDEN.filter((re) => re.test(text)).map((re) => re.source);
const coldLines = o.variant_a_cold.split(/\n/).filter((l) => l.trim()).length;
const l1_pass = coldLines <= 3 && o.variant_a_cold.length <= 320;

if (l0_hits.length) {
  return [{ json: { ok: false, l0_pass: false, l1_pass, l0_hits, error: 'L0_FORBIDDEN' } }];
}
if (!l1_pass) {
  return [{ json: { ok: false, l0_pass: true, l1_pass: false, error: 'L1_LENGTH' } }];
}

return [{ json: { ...item, l0_pass: true, l1_pass: true, l0_hits: [] } }];

